/**
 * Check if a ticker has static returns data
 */
export function hasStaticReturns(ticker) {
  return ticker in STATIC_RETURNS_DATA;
}

/**
 * Get static returns for a ticker
 * @returns {{ returns: number[], dates: string[] } | null}
 */
export function getStaticReturns(ticker) {
  const data = STATIC_RETURNS_DATA[ticker];
  if (!data) return null;
  return { returns: [...data.returns], dates: [...data.dates] };
}
